  ('social-worker-moex-01615', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者是治療會議（treatment conferences）的例子？', '["某醫院精神科的專業人員一起討論有關病患的治療計畫", "學校學生輔導人員、少年福利服務中心的社工人員，以及一位精神科醫生第二次聚會，討論某 位少年的處遇計畫", "在一所復健醫院，專業者和半專業者為中風病人一起討論治療計畫", "市立心理衛生中心贊助專業及半專業的工作人員，接受危機介入的訓練"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01616', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者並非支持性團體？', '["兒童團體成員討論父母離婚對他們的影響", "癌症患者聚會討論疾病對他們的影響，以及如何面對", "單親父母團體討論獨自養育孩子的辛苦", "醫院為有藥癮的人所組成的團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01617', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '任務性團體的最終目的是：', '["討論問題", "完成工作目標", "順利執行工作", "滿足團體成員需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01618', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作的歷史發展，下列何者錯誤？', '["政治科學家Mary P. Follett和思想家John Dewey二者的觀點對早期的工作者產生相當的影響", "最初團體工作與社區發展的概念沒有密切地關聯", "從1928年至第二次世界大戰結束，團體工作能有更進一步的發展主要受二個重要的社會變動 之影響，一為經濟不景氣；二為戰爭", "1946年之後Coyle在全美社會工作會議上將社會團體工作視為社會工作的一種工作方法，此觀 點並促成美國團體工作者協會的成立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01619', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '認知重建理論（Cognitive Restructuring Therapies）所提及「自我對話」（self-talk）工作方法，下 列何者正確？', '["「自我對話」是指中斷干擾性思考，以非干擾性思考取代干擾性的思考", "當人們思考時對自己說什麼，包含自我覺察、學習監測、以適合方式取代失靈部分", "鼓勵案主記錄特定行為所導致的現象", "自我對話的重點是增加與他人對話頻率、期間和持續程度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01620', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會目標模型（social goals model）的運用，下列敘述何者錯誤？', '["該模型相當類似社區工作，利用草根領導來解決社區問題", "在理念與工作方法上與個案工作的方法有不少共同點", "工作重點放在充權策略（empowerment strategies），對團體工作有很重大的貢獻", "該模型主張團體民主化的原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
